import { GoogleGenAI, Type } from "@google/genai";
import { MarketingData } from "../types";

export class GeminiService {
  private ai: GoogleGenAI;

  constructor() {
    this.ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
  }

  async generateMarketingIntelligence(data: MarketingData) {
    const prompt = `
      Act as ARIVUOPS AI. You are the CMO + CFO of ArivuPro Academy.
      Analyze the provided marketing operations data and generate a decision-ready executive intelligence report.

      Input Data:
      ${JSON.stringify(data, null, 2)}

      STRICT RULES:
      1. Detect waste and inefficiencies.
      2. Compute ROI and compute admission probability based on conversions.
      3. Identify top 20% performers and bottom 20% leakage.
      4. Score the team based on SLA and impact.
      5. Map everything to REVENUE or COST SAVING.

      EXECUTIVE DASHBOARD OUTPUT FORMAT:
      Your response must be in valid JSON format matching the schema provided.
    `;

    try {
      const response = await this.ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              summary: { type: Type.STRING, description: "High-level CMO executive summary" },
              wins: { type: Type.ARRAY, items: { type: Type.STRING }, description: "Key wins of the week" },
              losses: { type: Type.ARRAY, items: { type: Type.STRING }, description: "Key losses or risks detected" },
              roiTable: { 
                type: Type.ARRAY, 
                items: { 
                  type: Type.OBJECT,
                  properties: {
                    channel: { type: Type.STRING },
                    roi: { type: Type.STRING },
                    cpl: { type: Type.STRING },
                    efficiency: { type: Type.STRING }
                  }
                } 
              },
              coursePerformance: {
                type: Type.ARRAY,
                items: {
                  type: Type.OBJECT,
                  properties: {
                    course: { type: Type.STRING },
                    profitability: { type: Type.STRING },
                    growth: { type: Type.STRING }
                  }
                }
              },
              teamScorecard: {
                type: Type.ARRAY,
                items: {
                  type: Type.OBJECT,
                  properties: {
                    name: { type: Type.STRING },
                    score: { type: Type.NUMBER },
                    remarks: { type: Type.STRING }
                  }
                }
              },
              actionPlan: { type: Type.ARRAY, items: { type: Type.STRING } },
              automationFixes: { type: Type.ARRAY, items: { type: Type.STRING } },
              contentIdeas: { type: Type.ARRAY, items: { type: Type.STRING } }
            },
            required: ["summary", "wins", "losses", "roiTable", "actionPlan"]
          }
        }
      });

      return JSON.parse(response.text || "{}");
    } catch (error) {
      console.error("Gemini AI Analysis Error:", error);
      throw error;
    }
  }
}

