import React from 'react';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, 
  LineChart, Line, AreaChart, Area, PieChart, Pie, Cell 
} from 'recharts';
import { MarketingData } from '../types';

interface DashboardProps {
  data: MarketingData;
}

const Dashboard: React.FC<DashboardProps> = ({ data }) => {
  const totalRevenue = data.crm.reduce((acc, curr) => acc + curr.revenue, 0);
  const totalLeads = data.crm.reduce((acc, curr) => acc + curr.leads, 0);
  const avgCPL = data.ads.reduce((acc, curr) => acc + curr.spend, 0) / totalLeads;
  const totalAdmissions = data.crm.reduce((acc, curr) => acc + curr.admissions, 0);
  const conversionRate = (totalAdmissions / totalLeads) * 100;

  const COLORS = ['#3b82f6', '#10b981', '#f59e0b', '#ef4444'];

  const leadSources = data.crm.map(item => ({
    name: item.source,
    value: item.leads
  }));

  const adPerf = data.ads.map(item => ({
    name: item.campaign,
    spend: item.spend / 1000,
    leads: item.leads
  }));

  const seoTrend = data.seo.slice(0, 5).map(item => ({
    name: item.keyword.substring(0, 10),
    impressions: item.impressions / 100
  }));

  return (
    <div className="space-y-6">
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        <KpiCard title="Total Revenue" value={`₹${(totalRevenue / 100000).toFixed(2)}L`} sub="Last 7 Days" icon="💰" color="text-blue-600" />
        <KpiCard title="Total Leads" value={totalLeads.toString()} sub="+12% vs LW" icon="📈" color="text-emerald-600" />
        <KpiCard title="Avg CPL" value={`₹${avgCPL.toFixed(0)}`} sub="-5% efficiency" icon="🔥" color="text-amber-600" />
        <KpiCard title="Conversion %" value={`${conversionRate.toFixed(1)}%`} sub="High Intent" icon="🎯" color="text-indigo-600" />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        <div className="bg-white p-6 rounded-3xl shadow-sm border border-slate-100">
          <h3 className="text-lg font-bold text-slate-800 mb-6">Ads Performance (Spend in '000 vs Leads)</h3>
          <div className="h-[300px]">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={adPerf}>
                <CartesianGrid strokeDasharray="3 3" stroke="#f1f5f9" vertical={false} />
                <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fill: '#64748b', fontSize: 12}} />
                <YAxis axisLine={false} tickLine={false} tick={{fill: '#64748b', fontSize: 12}} />
                <Tooltip 
                  contentStyle={{ borderRadius: '12px', border: 'none', boxShadow: '0 10px 15px -3px rgb(0 0 0 / 0.1)' }}
                />
                <Bar dataKey="spend" fill="#3b82f6" radius={[4, 4, 0, 0]} name="Spend (K)" />
                <Bar dataKey="leads" fill="#10b981" radius={[4, 4, 0, 0]} name="Leads" />
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>

        <div className="bg-white p-6 rounded-3xl shadow-sm border border-slate-100">
          <h3 className="text-lg font-bold text-slate-800 mb-6">Lead Distribution by Source</h3>
          <div className="h-[300px] flex items-center justify-center">
            <ResponsiveContainer width="100%" height="100%">
              <PieChart>
                <Pie
                  data={leadSources}
                  cx="50%"
                  cy="50%"
                  innerRadius={60}
                  outerRadius={80}
                  paddingAngle={5}
                  dataKey="value"
                >
                  {leadSources.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                  ))}
                </Pie>
                <Tooltip />
              </PieChart>
            </ResponsiveContainer>
            <div className="w-1/3 space-y-2">
              {leadSources.map((item, idx) => (
                <div key={idx} className="flex items-center gap-2">
                  <div className="w-3 h-3 rounded-full" style={{ backgroundColor: COLORS[idx % COLORS.length] }}></div>
                  <span className="text-xs font-medium text-slate-600 truncate">{item.name}</span>
                </div>
              ))}
            </div>
          </div>
        </div>
      </div>

      <div className="bg-white p-6 rounded-3xl shadow-sm border border-slate-100">
        <h3 className="text-lg font-bold text-slate-800 mb-6">SEO Momentum (Top Keywords Impressions Index)</h3>
        <div className="h-[300px]">
          <ResponsiveContainer width="100%" height="100%">
            <AreaChart data={seoTrend}>
              <defs>
                <linearGradient id="colorImp" x1="0" y1="0" x2="0" y2="1">
                  <stop offset="5%" stopColor="#3b82f6" stopOpacity={0.1}/>
                  <stop offset="95%" stopColor="#3b82f6" stopOpacity={0}/>
                </linearGradient>
              </defs>
              <CartesianGrid strokeDasharray="3 3" stroke="#f1f5f9" vertical={false} />
              <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fill: '#64748b', fontSize: 12}} />
              <YAxis axisLine={false} tickLine={false} tick={{fill: '#64748b', fontSize: 12}} />
              <Tooltip />
              <Area type="monotone" dataKey="impressions" stroke="#3b82f6" strokeWidth={2} fillOpacity={1} fill="url(#colorImp)" />
            </AreaChart>
          </ResponsiveContainer>
        </div>
      </div>
    </div>
  );
};

const KpiCard = ({ title, value, sub, icon, color }: any) => (
