    <div>
      <p className="text-xs font-semibold text-slate-500 uppercase tracking-wider">{title}</p>
      <p className={`text-2xl font-extrabold ${color} mt-1`}>{value}</p>
      <p className="text-[10px] text-slate-400 mt-1 font-medium">{sub}</p>
    </div>
    <div className="text-3xl bg-slate-50 w-12 h-12 flex items-center justify-center rounded-2xl">{icon}</div>
  </div>
);

export default Dashboard;

